// Set Inputs â€” Agent 4: Cover Letter Verifier
const trigger = $input.item.json;

function strip(val) {
  if (val === null || val === undefined) return '';
  if (typeof val !== 'string') return val;
  let cleaned = val;
  while (cleaned.length > 0 && cleaned.charAt(0) === '=') {
    cleaned = cleaned.substring(1);
  }
  return cleaned;
}

const config = trigger.config || {};
const systemPrompt = strip(trigger.system_prompt);
const company = strip(trigger.company);
const title = strip(trigger.title);
const descriptionHtml = strip(trigger.description_html);
const coverLetterMarkdown = strip(trigger.cover_letter_markdown);
const masterDoc = strip(trigger.master_doc);

const provider = strip(config.provider_cover_letter_verifier);
if (!provider) {
  throw new Error('[Agent 4] config.provider_cover_letter_verifier is required. Set it in your config sheet (anthropic | openai | gemini).');
}

const model = strip(config.model_cover_letter_verifier);
if (!model) {
  throw new Error('[Agent 4] config.model_cover_letter_verifier is required. Set it in your config sheet.');
}

const maxTokens = Number(config.max_tokens_cover_letter_verifier);
if (!maxTokens || Number.isNaN(maxTokens)) {
  throw new Error('[Agent 4] config.max_tokens_cover_letter_verifier is required and must be a number.');
}

console.log(`[Agent 4 Set Inputs] cover_letter_markdown: ${coverLetterMarkdown.length} chars, master_doc: ${masterDoc.length} chars, provider: ${provider}, model: ${model}`);

return {
  json: {
    config,
    system_prompt: systemPrompt,
    company,
    title,
    description_html: descriptionHtml,
    cover_letter_markdown: coverLetterMarkdown,
    master_doc: masterDoc,
    provider,
    model,
    max_tokens: maxTokens
  }
};

// Agent 4: format output as standard envelope
// Mode: Run Once for All Items
// Robust JSON extraction handles trailing text, code fences, narrative wrapping
// Propagates structured error from Call LLM on failure.

const llmResponse = $input.first().json;

// Call LLM failed â€” propagate error without parse attempts on empty content
if (llmResponse.success === false) {
  console.log(`[Agent 4] LLM call failed: ${llmResponse.error?.category || 'unknown'} â€” ${llmResponse.error?.message || 'no message'}`);
  return [{
    json: {
      success: false,
      result: {},
      tokens: {
        input: llmResponse.input_tokens || 0,
        output: llmResponse.output_tokens || 0
      },
      cached_input_tokens: llmResponse.cached_input_tokens || 0,
      cache_write_tokens: llmResponse.cache_write_tokens || 0,
      model_used: llmResponse.model_used || 'unknown',
      provider_used: llmResponse.provider_used || 'unknown',
      errors: [...(llmResponse.errors || [])],
      error: llmResponse.error || {
        category: 'unknown',
        type: 'unknown',
        message: 'Call LLM returned success: false with no error object',
        provider: llmResponse.provider_used || 'unknown',
        model: llmResponse.model_used || 'unknown'
      }
    }
  }];
}

// Normal path: parse JSON from content
const rawContent = (llmResponse.content || '').trim();

// Robust JSON extractor â€” finds first { and walks to matching }
// Respects string literals and escapes
const extractJSON = (text) => {
  let cleaned = text
    .replace(/^```(?:json)?\s*\n?/i, '')
    .replace(/\n?```\s*$/i, '')
    .trim();

  try {
    return JSON.parse(cleaned);
  } catch (e) {
    // Fall through to extraction
  }

  const firstBrace = cleaned.indexOf('{');
  if (firstBrace === -1) return null;

  let depth = 0;
  let inString = false;
  let escape = false;
  let lastBrace = -1;

  for (let i = firstBrace; i < cleaned.length; i++) {
    const c = cleaned[i];
    if (escape) { escape = false; continue; }
    if (c === '\\') { escape = true; continue; }
    if (c === '"') { inString = !inString; continue; }
    if (inString) continue;
    if (c === '{') depth++;
    if (c === '}') {
      depth--;
      if (depth === 0) {
        lastBrace = i;
        break;
      }
    }
  }

  if (lastBrace === -1) return null;

  const jsonStr = cleaned.slice(firstBrace, lastBrace + 1);
  try {
    return JSON.parse(jsonStr);
  } catch (e) {
    return null;
  }
};

let verdict = null;
const parseErrors = [];

try {
  verdict = extractJSON(rawContent);
  if (!verdict) {
    parseErrors.push(`Could not extract valid JSON from LLM response`);
    console.log(`[Agent 4] Raw content (first 500 chars):\n${rawContent.slice(0, 500)}`);
  }
} catch (err) {
  const errMsg = err instanceof Error ? err.message : String(err);
  parseErrors.push(`Failed to extract JSON: ${errMsg}`);
  console.log(`[Agent 4] JSON parse failed. Raw content:\n${rawContent.slice(0, 500)}`);
}

const success = verdict !== null;
const errors = [...(llmResponse.errors || []), ...parseErrors];
const error = success ? null : {
  category: 'output_quality',
  type: 'json_parse_failure',
  message: parseErrors.join('; ') || 'Could not extract valid JSON from LLM response',
  provider: llmResponse.provider_used || 'unknown',
  model: llmResponse.model_used || 'unknown'
};

console.log(`[Agent 4] Verdict: ${verdict?.verdict || 'parse failed'}`);
console.log(`[Agent 4] Claims: ${verdict?.supported_count || 0}/${verdict?.claim_count || 0} supported`);
console.log(`[Agent 4] Tokens: ${llmResponse.input_tokens || 0}in + ${llmResponse.output_tokens || 0}out + ${llmResponse.cached_input_tokens || 0}cached + ${llmResponse.cache_write_tokens || 0}cache_write`);

return [{
  json: {
    success,
    result: verdict || {},
    tokens: {
      input: llmResponse.input_tokens || 0,
      output: llmResponse.output_tokens || 0
    },
    cached_input_tokens: llmResponse.cached_input_tokens || 0,
    cache_write_tokens: llmResponse.cache_write_tokens || 0,
    model_used: llmResponse.model_used || 'unknown',
    provider_used: llmResponse.provider_used || 'unknown',
    errors,
    error
  }
}];

// Build Prompt â€” Agent 4: Cover Letter Verifier
// Persona and verification rules live in system_prompt (prompts tab, agent_4).
// This node injects the OUTPUT CONTRACT (JSON schema + today's date +
// factual-vs-strategic distinction) and the per-job inputs.
// Severity is reported in full (critical/major/minor); the dashboard decides
// what to surface vs. collapse. No producer-side severity filtering â€” aligned
// with the resume verifier (agent_3).
// Mode: Run Once for Each Item
const input = $input.item.json;
const coverletterMarkdown = input.cover_letter_markdown || '';
const masterDoc = input.master_doc || '';
const provider = input.provider;
const model = input.model;
const maxTokens = input.max_tokens;
const systemPromptFromDoc = input.system_prompt || '';
// Validation
if (!systemPromptFromDoc || systemPromptFromDoc.length < 100) {
  throw new Error(`[Agent 4] system_prompt missing or too short (${systemPromptFromDoc.length} chars). Check Prompt Loader output and orchestrator mapping.`);
}
if (!masterDoc || masterDoc.length < 100) {
  throw new Error(`[Agent 4] master_doc missing or too short (${masterDoc.length} chars)`);
}
if (!coverletterMarkdown || coverletterMarkdown.length < 30) {
  throw new Error(`[Agent 4] cover_letter_markdown missing or too short (${coverletterMarkdown.length} chars)`);
}
const today = new Date().toISOString().split('T')[0];
console.log(`[Build Prompt] master_doc: ${masterDoc.length} chars, document: ${coverletterMarkdown.length} chars`);
console.log(`[Build Prompt] systemPromptFromDoc: ${systemPromptFromDoc.length} chars`);
// Pipeline-level output contract:
// - JSON schema downstream depends on
// - Today's date for runtime grounding
// - Factual-vs-strategic distinction (essential for cover letter verification)
// Severity scale matches the resume verifier: critical/major/minor, reported in full.
const OUTPUT_CONTRACT = `# OUTPUT CONTRACT (set by pipeline, do not override)

Today's date is ${today}. Trust the master doc's stated dates; do not assume dates are typos or future fabrications.

## Factual vs strategic framing (verifier scope)
Cover letters mix factual claims (must trace to master doc) with strategic framing (the candidate's perspective on the role or company). VERIFY factual claims; IGNORE strategic framing.

- FACTUAL CLAIM (verify): "I led product strategy for Amazon's image moderation platform that generated $30M+ in annual revenue."
- STRATEGIC FRAMING (ignore): "I'd sequence first around the subscription lifecycle." or "The leverage point here is governance, not tooling."

claim_count and unsupported_count should reflect ONLY factual claims.

## Severity
Assign every flagged factual claim an honest severity of "critical", "major", or "minor" per the SEVERITY GUIDANCE in your instructions. Report ALL unsupported factual claims at every severity â€” do not omit minor ones. The unsupported_count must equal the number of items in the issues array.

## Output JSON schema
Return ONLY valid JSON, no markdown wrapping, no preamble. Use this exact shape:

{
  "verdict": "clean" or "hallucinations_found",
  "summary": "<one-sentence overview>",
  "claim_count": <integer total factual claims checked>,
  "supported_count": <integer>,
  "unsupported_count": <integer>,
  "issues": [
    {
      "section": "greeting" or "body" or "signoff",
      "claim": "<verbatim text from cover letter>",
      "issue_type": "fabricated_company" or "fabricated_metric" or "fabricated_role" or "fabricated_skill" or "other",
      "severity": "critical" or "major" or "minor",
      "explanation": "<one-sentence explanation of why this isn't supported>"
    }
  ]
}

List issues in severity order: all critical first, then major, then minor.

If everything is clean, return:
{
  "verdict": "clean",
  "summary": "All factual claims supported by master career document.",
  "claim_count": <N>,
  "supported_count": <N>,
  "unsupported_count": 0,
  "issues": []
}`;
const system = systemPromptFromDoc + '\n\n' + OUTPUT_CONTRACT;
const userMessage = `Examine the cover letter below for fabrication. Compare specific factual claims against the master career document.

# CANDIDATE'S MASTER CAREER DOCUMENT (ground truth)

${masterDoc}

# GENERATED COVER LETTER TO VERIFY

${coverletterMarkdown}`;
console.log(`[Build Prompt] Final system: ${system.length} chars, user: ${userMessage.length} chars`);
return {
  json: {
    provider,
    model,
    system,
    user_message: userMessage,
    max_tokens: maxTokens,
    prompt_chars: system.length + userMessage.length
  }
};

// Build Cascade Output â€” Agent 4
// Mode: Run Once for All Items
// Fires when upstream agent failed. Passes upstream error through unchanged.
// `cascaded: true` flag lets Log Job Result dedupe (don't re-log original failures).

const trigger = $('Trigger').first().json;
const upstreamError = trigger.cascade_error || {};

console.log(`[Agent 4] CASCADE â€” skipping due to ${upstreamError.source_agent || 'upstream'}: ${upstreamError.category || 'unknown'}`);

return [{
  json: {
    success: false,
    cascaded: true,
    result: {},
    tokens: { input: 0, output: 0 },
    cached_input_tokens: 0,
    cache_write_tokens: 0,
    model_used: 'skipped',
    provider_used: 'skipped',
    errors: [`cascade: ${upstreamError.source_agent || 'upstream'}:${upstreamError.category || 'unknown'}`],
    error: upstreamError
  }
}];
